graphql.query:
query MeQuery {
  me {
    id
    userName
    memberId
    isAdministrator
  }
}

mutation ClearDefaultCart($cmd: InputClearCartType!) {
  clearCart(command: $cmd) {
    id
    itemsCount
    name
  }
}

query FindSavedForLaterCart($storeId: String!, $userId: String!) {
  cart(
    storeId: $storeId
    userId: $userId
    currencyCode: "USD"
    cultureName: "en-US"
    cartName: "Saved for later"
  ) {
    id
    name
    itemsCount
  }
}

mutation AddItemA($cmd: InputAddItemType!) {
  addItem(command: $cmd) {
    id
    itemsCount
  }
}

mutation AddItemB($cmd: InputAddItemType!) {
  addItem(command: $cmd) {
    id
    itemsCount
  }
}

mutation AddItemC($cmd: InputAddItemType!) {
  addItem(command: $cmd) {
    id
    itemsCount
  }
}

query ReadCart($storeId: String!, $userId: String!) {
  cart(
    storeId: $storeId
    userId: $userId
    currencyCode: "USD"
    cultureName: "en-US"
    cartName: "default"
  ) {
    id
    name
    itemsCount
    items {
      id
      productId
      quantity
      listPrice { amount formattedAmount }
      configurationItems {
        sectionId
        type
        productId
        customText
      }
    }
  }
}

mutation MoveAllToSaved($cmd: InputSaveForLaterType!) {
  moveToSavedForLater(command: $cmd) {
    cart { id itemsCount }
    list {
      id
      name
      itemsCount
      items {
        id
        productId
        quantity
        configurationItems {
          sectionId
          type
          productId
          customText
        }
      }
    }
  }
}

mutation MoveOneBackFromSaved($cmd: InputSaveForLaterType!) {
  moveFromSavedForLater(command: $cmd) {
    cart {
      id
      itemsCount
      items {
        id
        productId
        listPrice { amount formattedAmount }
        configurationItems {
          sectionId
          type
          productId
          customText
        }
      }
    }
    list { id itemsCount }
  }
}

query GetSavedForLater($storeId: String!, $userId: String!) {
  getSavedForLater(storeId: $storeId, userId: $userId, currencyCode: "USD") {
    id
    name
    itemsCount
    items {
      id
      productId
      quantity
      listPrice { amount formattedAmount }
      configurationItems {
        sectionId
        type
        productId
        customText
        selectedForCheckout
      }
    }
  }
}

mutation ClearDefaultCart($cmd: InputClearCartType!) {
