# This request is a 4-step chain. In Postman, run it in Collection Runner order:
# Step 1 = addItem text_a, Step 2 = removeCartItem, Step 3 = addItem text_b, Step 4 = read cart.
# For ad-hoc use, run the addItem text_b mutation below and check the test-script asserts.
mutation AddItemTextB($cmd: InputAddItemType!) {
  addItem(command: $cmd) {
    id
    itemsCount
    items {
      id
      productId
      quantity
      configurationItems { sectionId type customText }
    }
  }
}

